/**
 * FOIL workload: CPU-bound work to exercise the optimized hot loop.
 * Simulates realistic request processing with compute, not just I/O.
 */

// Hash-like computation
function hashString(s: string, seed = 5381): number {
  let hash = seed;
  for (let i = 0; i < s.length; i++) {
    hash = ((hash << 5) + hash) ^ s.charCodeAt(i);
  }
  return hash >>> 0;
}

// Fibonacci-like computation (CPU work)
function computeLoad(n: number): number {
  if (n <= 2) return 1;
  let a = 1, b = 1;
  for (let i = 2; i < n; i++) {
    [a, b] = [b, a + b];
  }
  return b;
}

// Simulate processing: hash + compute
function processRequest(userId: string, depth: number): string {
  const hash = hashString(userId);
  const compute = computeLoad(depth);

  // Do some string processing too
  const results = [];
  for (let i = 0; i < 10; i++) {
    results.push(`${userId}:${hash}:${compute}:${i}`);
  }

  return results.join('|');
}

/**
 * Handles the gnosis app workflow.
 */
export async function app(input: { userId: string; depth?: number }): Promise<string> {
  const depth = input.depth ?? 20; // Default compute depth
  return processRequest(input.userId, depth);
}
